import java.io.Serializable;

public class Account implements Serializable {
    private String accountNumber;
    private String accountHolderName;
    private double balance;
    private String pin;

    public Account(String accountNumber, String accountHolderName, double balance, String pin) {
        this.accountNumber = accountNumber;
        this.accountHolderName = accountHolderName;
        this.balance = balance;
        this.pin = pin;
    }

    public String getAccountNumber() { return accountNumber; }
    public String getAccountHolderName() { return accountHolderName; }
    public double getBalance() { return balance; }
    public String getPin() { return pin; }
    
    public void setBalance(double balance) { this.balance = balance; }
    
    public boolean validatePin(String inputPin) {
        return this.pin.equals(inputPin);
    }
}

// TransactionManager.java
import android.content.Context;
import android.content.SharedPreferences;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

public class TransactionManager {
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String ACCOUNT_KEY = "account_";
    private static final String BALANCE_KEY = "balance_";
    private static final String PIN_KEY = "pin_";
    private static final String NAME_KEY = "name_";
    
    private Context context;
    private SharedPreferences sharedPreferences;
    private List<Transaction> transactionHistory;

    public TransactionManager(Context context) {
        this.context = context;
        this.sharedPreferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        this.transactionHistory = new ArrayList<>();
    }

    public Account getAccount(String accountNumber) {
        String name = sharedPreferences.getString(NAME_KEY + accountNumber, null);
        if (name == null) return null;
        
        double balance = Double.parseDouble(sharedPreferences.getString(BALANCE_KEY + accountNumber, "0"));
        String pin = sharedPreferences.getString(PIN_KEY + accountNumber, "");
        
        return new Account(accountNumber, name, balance, pin);
    }

    public void saveAccount(Account account) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(NAME_KEY + account.getAccountNumber(), account.getAccountHolderName());
        editor.putString(BALANCE_KEY + account.getAccountNumber(), String.valueOf(account.getBalance()));
        editor.putString(PIN_KEY + account.getAccountNumber(), account.getPin());
        editor.apply();
    }

    public boolean processDeposit(String accountNumber, double amount, String pin) {
        Account account = getAccount(accountNumber);
        if (account == null || !account.validatePin(pin)) {
            return false;
        }

        if (amount <= 0) {
            return false;
        }

        account.setBalance(account.getBalance() + amount);
        saveAccount(account);

        Transaction transaction = new Transaction(
            UUID.randomUUID().toString(),
            accountNumber,
            amount,
            "DEPOSIT",
            "Deposit to account"
        );
        transactionHistory.add(transaction);

        return true;
    }

    public boolean processWithdrawal(String accountNumber, double amount, String pin) {
        Account account = getAccount(accountNumber);
        if (account == null || !account.validatePin(pin)) {
            return false;
        }

        if (amount <= 0 || account.getBalance() < amount) {
            return false;
        }

        account.setBalance(account.getBalance() - amount);
        saveAccount(account);

        Transaction transaction = new Transaction(
            UUID.randomUUID().toString(),
            accountNumber,
            amount,
            "WITHDRAWAL",
            "Withdrawal from account"
        );
        transactionHistory.add(transaction);

        return true;
    }

    public boolean processTransfer(String fromAccount, String toAccount, double amount, String pin) {
        Account from = getAccount(fromAccount);
        Account to = getAccount(toAccount);
        
        if (from == null || to == null || !from.validatePin(pin)) {
            return false;
        }

        if (amount <= 0 || from.getBalance() < amount) {
            return false;
        }

        from.setBalance(from.getBalance() - amount);
        to.setBalance(to.getBalance() + amount);
        
        saveAccount(from);
        saveAccount(to);

        Transaction debitTransaction = new Transaction(
            UUID.randomUUID().toString(),
            fromAccount,
            amount,
            "TRANSFER_OUT",
            "Transfer to " + toAccount
        );
        transactionHistory.add(debitTransaction);

        Transaction creditTransaction = new Transaction(
            UUID.randomUUID().toString(),
            toAccount,
            amount,
            "TRANSFER_IN",
            "Transfer from " + fromAccount
        );
        transactionHistory.add(creditTransaction);

        return true;
    }

    public double getBalance(String accountNumber, String pin) {
        Account account = getAccount(accountNumber);
        if (account == null || !account.validatePin(pin)) {
            return -1;
        }
        return account.getBalance();
    }

    public List<Transaction> getTransactionHistory() {
        return new ArrayList<>(transactionHistory);
    }

    public List<Transaction> getTransactionHistory(String accountNumber) {
        List<Transaction> accountTransactions = new ArrayList<>();
        for (Transaction transaction : transactionHistory) {
            if (transaction.getAccountNumber().equals(accountNumber)) {
                accountTransactions.add(transaction);
            }
        }
        return accountTransactions;
    }
}

// MainActivity.java
import android.app.Activity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class MainActivity extends Activity {
    
    private TransactionManager transactionManager;
    private EditText accountNumberInput;
    private EditText pinInput;
    private EditText amountInput;
    private EditText toAccountInput;
    private TextView balanceDisplay;
    private Button checkBalanceButton;
    private Button depositButton;
    private Button withdrawButton;
    private Button transferButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        transactionManager = new TransactionManager(this);
        
        initializeViews();
        setupListeners();
        createDemoAccounts();
    }

    private void initializeViews() {
        accountNumberInput = findViewById(R.id.accountNumberInput);
        pinInput = findViewById(R.id.pinInput);
        amountInput = findViewById(R.id.amountInput);
        toAccountInput = findViewById(R.id.toAccountInput);
        balanceDisplay = findViewById(R.id.balanceDisplay);
        checkBalanceButton = findViewById(R.id.checkBalanceButton);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        transferButton = findViewById(R.id.transferButton);
    }

    private void setupListeners() {
        checkBalanceButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                checkBalance();
            }
        });

        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processDeposit();
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processWithdrawal();
            }
        });

        transferButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransfer();
            }
        });
    }

    private void createDemoAccounts() {
        Account account1 = new Account("1001", "John Doe", 5000.00, "1234");
        Account account2 = new Account("1002", "Jane Smith", 3000.00, "5678");
        
        transactionManager.saveAccount(account1);
        transactionManager.saveAccount(account2);
    }

    private void checkBalance() {
        String accountNumber = accountNumberInput.getText().toString();
        String pin = pinInput.getText().toString();

        if (accountNumber.isEmpty() || pin.isEmpty()) {
            Toast.makeText(this, "Please enter account number and PIN", Toast.LENGTH_SHORT).show();
            return;
        }

        double balance = transactionManager.getBalance(accountNumber, pin);
        
        if (balance < 0) {
            Toast.makeText(this, "Invalid account or PIN", Toast.LENGTH_SHORT).show();
            balanceDisplay.setText("Balance: N/A");
        } else {
            balanceDisplay.setText("Balance: $" + String.format("%.2f", balance));
        }
    }

    private void processDeposit() {
        String accountNumber = accountNumberInput.getText().toString();
        String pin = pinInput.getText().toString();
        String amountStr = amountInput.getText().toString();

        if (accountNumber.isEmpty() || pin.isEmpty() || amountStr.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }

        try {
            double amount = Double.parseDouble(amountStr);
            boolean success = transactionManager.processDeposit(accountNumber, amount, pin);
            
            if (success) {
                Toast.makeText(this, "Deposit successful", Toast.LENGTH_SHORT).show();
                checkBalance();
                amountInput.setText("");
            } else {
                Toast.makeText(this, "Deposit failed", Toast.LENGTH_SHORT).show();
            }
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid amount", Toast.LENGTH_SHORT).show();
        }
    }

    private void processWithdrawal() {
        String accountNumber = accountNumberInput.getText().toString();
        String pin = pinInput.getText().toString();
        String amountStr = amountInput.getText().toString();

        if (accountNumber.isEmpty() || pin.isEmpty() || amountStr.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }

        try {
            double amount = Double.parseDouble(amountStr);
            boolean success = transactionManager.processWithdrawal(accountNumber, amount, pin);
            
            if (success) {
                Toast.makeText(this, "Withdrawal successful", Toast.LENGTH_SHORT).show();
                checkBalance();
                amountInput.setText("");
            } else {
                Toast.makeText(this, "Withdrawal failed - insufficient funds or invalid PIN", Toast.LENGTH_SHORT).show();
            }
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid amount", Toast.LENGTH_SHORT).show();
        }
    }

    private void processTransfer() {
        String fromAccount = accountNumberInput.getText().toString();
        String toAccount = toAccountInput.getText().toString();
        String pin = pinInput.getText().toString();
        String amountStr = amountInput.getText().toString();

        if (fromAccount.isEmpty() || toAccount.isEmpty() || pin.isEmpty() || amountStr.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }

        try {
            double amount = Double.parseDouble(amountStr);
            boolean success = transactionManager.processTransfer(fromAccount, toAccount, amount, pin);
            
            if (success) {
                Toast.makeText(this, "Transfer successful", Toast.LENGTH_SHORT).show();
                checkBalance();
                amountInput.setText("");
                toAccountInput.setText("");
            } else {
                Toast.makeText(this, "Transfer failed", Toast.LENGTH_SHORT).show();
            }
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid amount", Toast.LENGTH_SHORT).show();
        }
    }
}

